import React from "react";
import { useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { addToCart, removeItem } from "./CartSlice";

function Non_Veg() {
  const cart = useSelector((state) => state.cart);
  const dispatch = useDispatch();

  // Add to Cart
  const handleAddToCart = (item) => {
    dispatch(addToCart({ ...item, id: 200 + item.id }));
  };
  
  const nonVegItems = [
    {
      id: 1,
      name: "Chicken Biryani",
      price:"300 RS",
      image: "data:image/jpeg;base64,",
      description: "Aromatic basmati rice cooked with spicy chicken and traditional Indian spices."
    },
    {
      id: 2,
      name: "Mutton Curry",
      price:"250 RS",
      image: "data:image/jpeg;base64,",
      description: "Tender mutton pieces slow-cooked in rich and flavorful gravy."
    },
    {
      id: 3,
      name: "Butter Chicken",
      price:"470 RS",
      image: "data:image/jpeg;base64,",
      description: "Creamy tomato-based curry with tender chicken pieces and rich buttery flavor."
    },
    {
      id: 4,
      name: "Chicken Tandoori",
      price:"400 RS",
      image: "data:image/jpeg;base64,",
      description: "Juicy chicken marinated in yogurt and spices, roasted in a tandoor."
    },
    {
      id: 5,
      name: "Fish Fry",
      price:"330 RS",
      image: "data:image/jpeg;base64,",
      description: "Crispy fried fish marinated with special coastal spices."
    },
    {
      id: 6,
      name: "Prawn Masala",
      price:"300 RS",
      image: "data:image/jpeg;base64,",
      description: "Spicy and flavorful prawns cooked in traditional Indian masala gravy."
    }
  ];
  
  return (
    <div style={{ padding: "20px" }}>
      <h2>Non_Veg Items</h2>

      <h3>🛒 Cart Items: {cart.length}</h3>

      <div style={{ display: "flex", gap: "20px", flexWrap: "wrap" }}>
        {nonVegItems.map((item) => (
          <div
            key={item.id}
            style={{
              border: "1px solid #0584af",
              borderRadius: "10px",
              width: "250px",
              padding: "10px",
              textAlign: "center"
            }}
          >
            <img
              src={item.image}
              alt={item.name}
              style={{ width: "100%", borderRadius: "10px" }}
            />

            <h3>{item.name}</h3>
            <h4>{item.price}</h4>
            <p>{item.description}</p>

            <button
              onClick={() => handleAddToCart(item)}
              style={{
                marginTop: "10px",
                padding: "8px",
                backgroundColor: "green",
                color: "white",
                border: "none",
                borderRadius: "5px",
                cursor: "pointer"
              }}
            >
              Add to Cart
            </button>
          </div>
        ))}
      </div>

      {/* Cart Section */}
      <h2 style={{ marginTop: "40px" }}>Cart</h2>

      {cart.length === 0 ? (
        <p>No items in cart</p>
      ) : (
        cart.map((item, index) => (
          <div
            key={index}
            style={{
              border: "1px solid gray",
              margin: "10px 0",
              padding: "10px",
              borderRadius: "5px",
              display: "flex",
              justifyContent: "space-between"
            }}
          >
            <span>
              {item.name} - {item.price}
            </span>

            <button
              onClick={() => dispatch(removeItem(item.id))}
              style={{
                backgroundColor: "red",
                color: "white",
                border: "none",
                padding: "5px 10px",
                borderRadius: "5px",
                cursor: "pointer"
              }}
            >
              Remove
            </button>
          </div>
        ))
      )}
    </div>
  );
}

export default Non_Veg;
